class Solution:
    def longestValidSubstring(self, word, forbidden):
        forb = set(forbidden)
        n = len(word)
        best = 0
        for i in range(n):
            for j in range(i, n):
                sub = word[i:j + 1]
                bad = False
                for f in forb:
                    if f in sub:
                        bad = True
                        break
                if bad:
                    break
                best = max(best, j - i + 1)
        return best

