class Solution:
    def longestValidSubstring(self, word, forbidden):
        forb = set(forbidden)
        max_len = max((len(f) for f in forb), default=0)
        n = len(word)
        left = 0
        best = 0
        for right in range(n):
            limit = min(max_len, right - left + 1)
            for length in range(1, limit + 1):
                sub = word[right - length + 1:right + 1]
                if sub in forb:
                    left = max(left, right - length + 2)
                    break
            best = max(best, right - left + 1)
        return best

