var longestValidSubstring = function(word, forbidden) {
    const forb = new Set(forbidden);
    let maxLen = 0;
    for (const f of forb) maxLen = Math.max(maxLen, f.length);
    const n = word.length;
    let left = 0;
    let best = 0;
    for (let right = 0; right < n; right++) {
        const limit = Math.min(maxLen, right - left + 1);
        for (let length = 1; length <= limit; length++) {
            const sub = word.slice(right - length + 1, right + 1);
            if (forb.has(sub)) {
                left = Math.max(left, right - length + 2);
                break;
            }
        }
        best = Math.max(best, right - left + 1);
    }
    return best;
};
